import{_ as a,o as r,c as o,ae as e}from"./chunks/framework.C8MNLDzb.js";const g=JSON.parse('{"title":"《静夜思》鉴赏","description":"","frontmatter":{},"headers":[],"relativePath":"ji/静夜思.md","filePath":"ji/静夜思.md"}'),l={name:"ji/静夜思.md"};function i(n,t,s,d,h,c){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="《静夜思》鉴赏" tabindex="-1">《静夜思》鉴赏 <a class="header-anchor" href="#《静夜思》鉴赏" aria-label="Permalink to &quot;《静夜思》鉴赏&quot;">​</a></h1><hr><h2 id="原文" tabindex="-1">原文 <a class="header-anchor" href="#原文" aria-label="Permalink to &quot;原文&quot;">​</a></h2><blockquote><p>床前明月光， 疑是地上霜。 举头望明月， 低头思故乡。</p></blockquote><hr><h2 id="作者简介" tabindex="-1">作者简介 <a class="header-anchor" href="#作者简介" aria-label="Permalink to &quot;作者简介&quot;">​</a></h2><p><strong>李白</strong>（701年—762年）</p><p>字太白，号青莲居士，唐代伟大的浪漫主义诗人，被誉为&quot;诗仙&quot;。</p><ul><li>其诗想象丰富，意境恢弘</li><li>代表作：《将进酒》《蜀道难》《静夜思》等</li><li>与杜甫并称&quot;李杜&quot;，为唐诗双璧</li></ul><hr><h2 id="诗歌赏析" tabindex="-1">诗歌赏析 <a class="header-anchor" href="#诗歌赏析" aria-label="Permalink to &quot;诗歌赏析&quot;">​</a></h2><h3 id="意象分析" tabindex="-1">意象分析 <a class="header-anchor" href="#意象分析" aria-label="Permalink to &quot;意象分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>意象</th><th>含义</th></tr></thead><tbody><tr><td>月光</td><td>澄澈清冷，照见心迹</td></tr><tr><td>霜</td><td>比喻月光之清冷，渲染秋夜气氛</td></tr><tr><td>明月</td><td>思乡的媒介，跨越空间的纽带</td></tr><tr><td>故乡</td><td>诗人内心最深处的牵挂</td></tr></tbody></table><h3 id="情感脉络" tabindex="-1">情感脉络 <a class="header-anchor" href="#情感脉络" aria-label="Permalink to &quot;情感脉络&quot;">​</a></h3><ol><li><strong>触景</strong> — 床前明月光，铺陈眼前所见</li><li><strong>生疑</strong> — 疑是地上霜，以假乱真</li><li><strong>仰望</strong> — 举头望明月，与故乡同月</li><li><strong>怀乡</strong> — 低头思故乡，情感升华</li></ol><h3 id="艺术特色" tabindex="-1">艺术特色 <a class="header-anchor" href="#艺术特色" aria-label="Permalink to &quot;艺术特色&quot;">​</a></h3><ul><li><strong>语言朴素</strong>：全诗仅二十字，却意蕴深远</li><li><strong>动静结合</strong>：举头/低头，静中有动</li><li><strong>虚实相生</strong>：月光与霜，明月与故乡</li><li><strong>以小见大</strong>：从一缕月光引出无限乡思</li></ul><hr><h2 id="名句地位" tabindex="-1">名句地位 <a class="header-anchor" href="#名句地位" aria-label="Permalink to &quot;名句地位&quot;">​</a></h2><p>《静夜思》是中国古代最短的思乡诗之一，也是流传最广的唐诗之一。它以极简的语言道出了人类共同的思乡情结，历经千年而魅力不减。</p><hr><p><strong>分类：</strong> 集部 <strong>体裁：</strong> 诗词 <strong>时代：</strong> 隋唐 <strong>作者：</strong> 李白 <strong>标签：</strong> 思乡、明月、唐诗、浪漫主义</p>',22)])])}const _=a(l,[["render",i]]);export{g as __pageData,_ as default};
